insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-swift', 'en', 'Common Swift', 'Swifts can stay airborne for months at a time, even sleeping on the wing.', 'On warm summer evenings, watch high over rooftops and listen for screaming parties.', 'Put up a swift box under your eaves before the birds return in spring.', 'When renovating, keep the small gaps under eaves where swifts nest.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-swift', 'sv', 'Tornseglare', 'Tornseglare kan hålla sig i luften i flera månader i sträck och sover till och med under flykten.', 'Under varma sommarkvällar, spana högt över hustaken och lyssna efter skrikande flockar.', 'Sätt upp en holk för tornseglare under takfoten innan fåglarna återvänder på våren.', 'Vid renovering, bevara de små springorna under takfoten där tornseglare häckar.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('barn-swallow', 'en', 'Barn Swallow', 'Barn swallows migrate all the way to southern Africa and back each year.', 'From spring to early autumn, look for them skimming low over open fields and water.', 'Leave a barn or shed door ajar so they can reach their nest ledges.', 'Avoid knocking down old mud nests — swallows reuse them year after year.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('barn-swallow', 'sv', 'Ladusvala', 'Ladusvalan flyttar ända till södra Afrika och tillbaka varje år.', 'Från vår till tidig höst, håll utkik efter dem när de svävar lågt över öppna fält och vatten.', 'Lämna en lad- eller skjulsdörr på glänt så att de når sina boplatser.', 'Undvik att riva gamla lerbon – svalor återanvänder dem år efter år.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-cuckoo', 'en', 'Common Cuckoo', 'Cuckoos lay their eggs in other birds’ nests and never raise their own young.', 'In late spring, listen for the far-carrying "cuck-oo" call from woodland edges.', 'Support insect-rich meadows and hedgerows that feed the birds cuckoos rely on.', 'Keep to paths near scrub and reedbeds so host birds are not disturbed.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-cuckoo', 'sv', 'Gök', 'Göken lägger sina ägg i andra fåglars bon och uppfostrar aldrig sina egna ungar.', 'På senvåren, lyssna efter det långväga ”ko-ko”-ropet från skogsbryn.', 'Stöd insektsrika ängar och häckar som föder de fåglar göken är beroende av.', 'Håll dig till stigarna nära buskmark och vassar så att värdfåglarna inte störs.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-robin', 'en', 'European Robin', 'Robins are fiercely territorial and will sing through the night near streetlights.', 'Year-round in gardens and woodland; they often follow diggers hoping for worms.', 'Leave a corner of the garden with leaf litter where robins can forage.', 'Delay heavy hedge-cutting until nesting is over in late summer.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-robin', 'sv', 'Rödhake', 'Rödhaken är hårt revirhävdande och kan sjunga natten igenom nära gatlyktor.', 'Året runt i trädgårdar och skog; de följer ofta efter grävande arbete i hopp om maskar.', 'Lämna ett hörn av trädgården med löv där rödhaken kan söka föda.', 'Skjut upp kraftig häckklippning tills häckningen är över på sensommaren.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-blackbird', 'en', 'Common Blackbird', 'The male’s rich, fluting song is one of the most recognisable in Europe.', 'Year-round; listen for males singing from rooftops and treetops at dawn and dusk.', 'Put out fresh water for drinking and bathing, especially in dry spells.', 'Keep cats indoors at dawn during the nesting season.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-blackbird', 'sv', 'Koltrast', 'Hanens rika, flöjtande sång är en av de mest igenkännliga i Europa.', 'Året runt; lyssna efter hanar som sjunger från tak och trädtoppar i gryning och skymning.', 'Ställ ut färskt vatten för dryck och bad, särskilt under torra perioder.', 'Håll katter inomhus i gryningen under häckningssäsongen.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('fieldfare', 'en', 'Fieldfare', 'Fieldfares are social thrushes that roam in noisy, chattering winter flocks.', 'In autumn and winter, watch flocks stripping berries from hedges and rowan trees.', 'Leave berry-bearing shrubs like rowan and hawthorn unpruned over winter.', 'Let windfall apples lie in winter — they are vital cold-weather food.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('fieldfare', 'sv', 'Björktrast', 'Björktrasten är en social trast som stryker omkring i högljudda, pratsamma vinterflockar.', 'Under höst och vinter, se flockar rensa bär från häckar och rönnar.', 'Lämna bärbärande buskar som rönn och hagtorn oklippta över vintern.', 'Låt fallfrukt ligga kvar på vintern – det är viktig föda i kylan.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('great-tit', 'en', 'Great Tit', 'Great tits have a huge vocabulary and learn new calls from their neighbours.', 'Year-round; listen for the ringing "teacher-teacher" song from late winter.', 'Hang a nest box with a 32 mm hole in a quiet, shaded spot.', 'Avoid garden pesticides so there are enough caterpillars to feed the chicks.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('great-tit', 'sv', 'Talgoxe', 'Talgoxar har ett stort läten-register och lär sig nya rop av sina grannar.', 'Året runt; lyssna efter den ringande ”ti-ta, ti-ta”-sången från senvintern.', 'Sätt upp en holk med 32 mm hål på en lugn, skuggig plats.', 'Undvik trädgårdsbekämpningsmedel så att det finns tillräckligt med larver till ungarna.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('blue-tit', 'en', 'Eurasian Blue Tit', 'A single brood of blue tits can eat over a thousand caterpillars.', 'Year-round in gardens and woods, often hanging upside-down on thin twigs.', 'Put up a small nest box with a 25 mm hole away from prevailing wind.', 'Skip insecticides in spring so caterpillars are available for the chicks.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('blue-tit', 'sv', 'Blåmes', 'En enda kull blåmesar kan äta över tusen larver.', 'Året runt i trädgårdar och skog, ofta hängande upp och ner på tunna kvistar.', 'Sätt upp en liten holk med 25 mm hål i lä för rådande vind.', 'Hoppa över insektsmedel på våren så att larver finns till ungarna.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-chaffinch', 'en', 'Common Chaffinch', 'Chaffinch songs vary by region, almost like local dialects.', 'Spring to autumn; males sing a bright, descending phrase from open perches.', 'Leave some seed heads and weedy patches standing over the season.', 'Keep feeders clean to prevent disease spreading among finches.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-chaffinch', 'sv', 'Bofink', 'Bofinkens sång varierar mellan regioner, nästan som lokala dialekter.', 'Vår till höst; hanar sjunger en ljus, fallande fras från öppna sittplatser.', 'Lämna en del fröställningar och ogräsfläckar stående under säsongen.', 'Håll fågelmatningar rena för att hindra att sjukdomar sprids bland finkar.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('eurasian-jay', 'en', 'Eurasian Jay', 'Jays bury thousands of acorns each autumn and plant whole oak woods by forgetting some.', 'Year-round in oak woodland; watch for flashes of pink and blue in autumn.', 'Leave fallen acorns and leaf litter under oaks undisturbed.', 'Keep dogs on paths in woodland so ground-feeding birds are not flushed.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('eurasian-jay', 'sv', 'Nötskrika', 'Nötskrikan gömmer tusentals ekollon varje höst och planterar hela ekskogar genom att glömma en del.', 'Året runt i ekskog; håll utkik efter skymtar av rosa och blått på hösten.', 'Lämna fallna ekollon och löv under ekar orörda.', 'Håll hundar på stigarna i skogen så att markfödande fåglar inte skräms upp.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('great-spotted-woodpecker', 'en', 'Great Spotted Woodpecker', 'Its spring "drumming" is not feeding but a fast tattoo to claim territory.', 'Year-round; in late winter listen for drumming echoing through the woods.', 'Leave standing dead wood, which holds the insects woodpeckers feed on.', 'Do not fell dead or dying trees that may hold nest holes.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('great-spotted-woodpecker', 'sv', 'Större hackspett', 'Dess vårtrummande är inte födosök utan en snabb trumvirvel för att hävda revir.', 'Året runt; lyssna på senvintern efter trummande som ekar genom skogen.', 'Lämna stående död ved, som hyser de insekter hackspettar äter.', 'Fäll inte döda eller döende träd som kan innehålla bohål.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('white-wagtail', 'en', 'White Wagtail', 'The wagtail’s constant tail-bobbing may signal alertness to predators.', 'Spring to autumn near water and open ground, running and pausing to snatch insects.', 'Keep a patch of short grass or gravel near water where they can forage.', 'Avoid disturbing shingle and shoreline where wagtails feed and nest.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('white-wagtail', 'sv', 'Sädesärla', 'Ärlans ständiga stjärtviftande kan signalera vaksamhet mot rovdjur.', 'Vår till höst nära vatten och öppen mark, springande och stannande för att fånga insekter.', 'Behåll en fläck kortklippt gräs eller grus nära vatten där de kan söka föda.', 'Undvik att störa grus- och strandkanter där ärlor söker föda och häckar.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-crane', 'en', 'Common Crane', 'Cranes perform leaping, bowing courtship dances in early spring.', 'From spring to autumn around wetlands; listen for bugling calls carrying for miles.', 'Support the protection of undrained bogs and wet meadows where cranes breed.', 'Watch nesting wetlands from a distance — cranes abandon disturbed nests.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-crane', 'sv', 'Trana', 'Tranor utför hoppande, bugande speldanser tidigt på våren.', 'Från vår till höst kring våtmarker; lyssna efter trumpetande rop som bär flera kilometer.', 'Stöd skyddet av odikade mossar och våta ängar där tranor häckar.', 'Betrakta häckningsvåtmarker på avstånd – tranor överger störda bon.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('whooper-swan', 'en', 'Whooper Swan', 'Whooper swans mate for life and announce arrivals with loud, trumpeting calls.', 'In spring and autumn on lakes and flooded fields, often in family groups.', 'Support keeping shallow lake margins and wet fields free of drainage.', 'Never feed bread to swans — it harms them; keep your distance on the ice.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('whooper-swan', 'sv', 'Sångsvan', 'Sångsvanar parar sig för livet och annonserar ankomster med höga, trumpetande rop.', 'Vår och höst på sjöar och översvämmade fält, ofta i familjegrupper.', 'Stöd att behålla grunda sjökanter och våta fält fria från dikning.', 'Mata aldrig svanar med bröd – det skadar dem; håll avstånd på isen.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('mallard', 'en', 'Mallard', 'Ducklings can swim and feed themselves within hours of hatching.', 'Year-round on almost any pond, lake, or slow river.', 'If you feed ducks, use oats, peas, or seeds rather than bread.', 'Keep dogs out of the water where ducks are nesting in spring.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('mallard', 'sv', 'Gräsand', 'Ungarna kan simma och söka föda själva bara timmar efter kläckningen.', 'Året runt på nästan vilken damm, sjö eller lugnt vattendrag som helst.', 'Om du matar änder, använd havre, ärtor eller frön i stället för bröd.', 'Håll hundar borta från vattnet där änder häckar på våren.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-buzzard', 'en', 'Common Buzzard', 'Buzzards soar on broad wings and often call with a cat-like "peee-yow".', 'Spring to autumn; scan for them circling high over fields and forest edges.', 'Support rough grassland and field margins that hold voles and small prey.', 'Never use rodent poisons, which move up the food chain into birds of prey.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-buzzard', 'sv', 'Ormvråk', 'Ormvråken svävar på breda vingar och ropar ofta med ett kattlikt ”pi-ää”.', 'Vår till höst; spana efter dem när de kretsar högt över fält och skogsbryn.', 'Stöd ängsmark och åkerkanter som hyser sorkar och smådjur.', 'Använd aldrig råttgift, som vandrar upp i näringskedjan till rovfåglar.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('osprey', 'en', 'Osprey', 'Ospreys plunge feet-first to catch fish and can carry prey half their own weight.', 'Spring to autumn near large lakes; watch for hovering then a dramatic dive.', 'Support artificial nest platforms on tall poles near fish-rich lakes.', 'Give nesting platforms a wide berth so pairs are not scared off their eggs.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('osprey', 'sv', 'Fiskgjuse', 'Fiskgjusen dyker med fötterna först för att fånga fisk och kan bära byte som väger hälften av den själv.', 'Vår till höst nära stora sjöar; håll utkik efter ryttling följt av ett dramatiskt dyk.', 'Stöd konstgjorda boplattformar på höga stolpar nära fiskrika sjöar.', 'Ge boplattformar gott om utrymme så att paren inte skräms från äggen.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('red-fox', 'en', 'Red Fox', 'Foxes use the Earth’s magnetic field to help judge pounces on hidden prey.', 'Year-round, most active at dawn and dusk along woodland and field edges.', 'Leave a wild, undisturbed corner where foxes can rest and den.', 'Secure bins and never leave harmful food scraps out for foxes.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('red-fox', 'sv', 'Rödräv', 'Rävar använder jordens magnetfält för att bedöma sina hopp mot dolt byte.', 'Året runt, mest aktiv i gryning och skymning längs skogs- och åkerkanter.', 'Lämna ett vilt, ostört hörn där rävar kan vila och gräva lya.', 'Säkra sopkärl och lämna aldrig skadliga matrester ute åt rävar.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-hedgehog', 'en', 'European Hedgehog', 'A hedgehog can travel a couple of kilometres in a single night’s foraging.', 'From spring to autumn after dark; in winter they hibernate under leaf and log piles.', 'Cut a 13 cm gap in fences so hedgehogs can roam between gardens.', 'Check long grass before strimming and leave leaf piles for hibernation.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-hedgehog', 'sv', 'Igelkott', 'En igelkott kan färdas ett par kilometer under en enda natts födosök.', 'Från vår till höst efter mörkrets inbrott; på vintern går de i ide under löv- och vedhögar.', 'Klipp ett 13 cm hål i staket så att igelkottar kan röra sig mellan trädgårdar.', 'Kolla högt gräs innan du trimmar och lämna lövhögar för vinteride.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('roe-deer', 'en', 'Roe Deer', 'Roe deer delay their pregnancy so fawns are always born in early summer.', 'Year-round at woodland edges, most visible grazing at dawn and dusk.', 'Support unmown field margins and scrub that give deer cover and food.', 'Keep dogs leashed near woodland in early summer when fawns lie hidden.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('roe-deer', 'sv', 'Rådjur', 'Rådjur fördröjer sin dräktighet så att killingarna alltid föds på försommaren.', 'Året runt i skogsbryn, mest synliga när de betar i gryning och skymning.', 'Stöd oklippta åkerkanter och buskmark som ger rådjur skydd och föda.', 'Håll hundar kopplade nära skog på försommaren när killingar ligger gömda.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('moose', 'en', 'Moose', 'The moose is the largest deer on Earth; a big bull can weigh over half a tonne.', 'Year-round in forests and wetlands, most active at dawn and dusk.', 'Support connected forests and wetland corridors that moose need to roam.', 'Drive carefully at dawn and dusk on forest roads and never approach a calf.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('moose', 'sv', 'Älg', 'Älgen är världens största hjortdjur; en stor tjur kan väga över ett halvt ton.', 'Året runt i skogar och våtmarker, mest aktiv i gryning och skymning.', 'Stöd sammanhängande skogar och våtmarkskorridorer som älgar behöver för att vandra.', 'Kör försiktigt i gryning och skymning på skogsvägar och närma dig aldrig en kalv.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('red-squirrel', 'en', 'Eurasian Red Squirrel', 'Red squirrels build several nests, called dreys, and move between them.', 'Year-round in conifer and mixed woods, busiest in the early morning.', 'Leave cones, nuts, and standing trees that squirrels feed and nest in.', 'Keep dogs on paths and avoid disturbing trees that may hold a drey.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('red-squirrel', 'sv', 'Ekorre', 'Ekorren bygger flera bon, kallade risbon, och flyttar mellan dem.', 'Året runt i barr- och blandskog, flitigast tidigt på morgonen.', 'Lämna kottar, nötter och stående träd som ekorrar äter och bor i.', 'Håll hundar på stigarna och undvik att störa träd som kan hysa ett risbo.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-beaver', 'en', 'European Beaver', 'Beaver dams create wetlands that boost fish, birds, and insects for miles.', 'From spring to late autumn around slow rivers, most active at dusk.', 'Support leaving beaver dams and waterside trees in place where safe.', 'Keep back from lodges and dams, especially when kits are young.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-beaver', 'sv', 'Bäver', 'Bäverdammar skapar våtmarker som gynnar fisk, fåglar och insekter i milsvida områden.', 'Från vår till sen höst kring lugna vattendrag, mest aktiv i skymningen.', 'Stöd att lämna bäverdammar och strandträd på plats där det är säkert.', 'Håll avstånd från hyddor och dammar, särskilt när kuttingarna är små.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('mountain-hare', 'en', 'Mountain Hare', 'Mountain hares turn white in winter for camouflage against the snow.', 'Year-round on open ground and forest clearings, mainly at dawn and dusk.', 'Support a mix of open ground and cover that hares need through the year.', 'Keep dogs leashed on open ground so resting hares are not chased.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('mountain-hare', 'sv', 'Skogshare', 'Skogsharen blir vit på vintern för att smälta in mot snön.', 'Året runt på öppen mark och skogsgläntor, främst i gryning och skymning.', 'Stöd en blandning av öppen mark och skydd som harar behöver året om.', 'Håll hundar kopplade på öppen mark så att vilande harar inte jagas.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-badger', 'en', 'European Badger', 'Badgers live in family groups in underground setts used for generations.', 'From spring to autumn after dark near woodland; they sleep away the winter.', 'Leave undisturbed banks and hedgerows where badgers can dig setts.', 'Never block or dig near an active sett — it is their long-term home.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-badger', 'sv', 'Grävling', 'Grävlingar lever i familjegrupper i underjordiska gryt som används i generationer.', 'Från vår till höst efter mörkrets inbrott nära skog; de sover bort vintern.', 'Lämna ostörda slänter och häckar där grävlingar kan gräva gryt.', 'Blockera eller gräv aldrig nära ett aktivt gryt – det är deras långvariga hem.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-pipistrelle', 'en', 'Common Pipistrelle', 'This tiny bat can eat up to 3,000 midges and mosquitoes in one night.', 'On summer evenings, watch for fast, jinking flight around dusk over gardens.', 'Put up a bat box high on a wall or tree that catches the evening sun.', 'Avoid bright lights on roost entrances and keep the night sky dark for bats.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-pipistrelle', 'sv', 'Dvärgpipistrell', 'Denna lilla fladdermus kan äta upp till 3 000 mygg på en natt.', 'Sommarkvällar, håll utkik efter snabb, sicksackande flykt i skymningen över trädgårdar.', 'Sätt upp en fladdermusholk högt på en vägg eller ett träd som fångar kvällssolen.', 'Undvik starkt ljus vid boplatser och håll natthimlen mörk för fladdermöss.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('small-tortoiseshell', 'en', 'Small Tortoiseshell', 'This butterfly hibernates as an adult, often in sheds and lofts.', 'From early spring to autumn on sunny flowers, especially nettles and buddleia.', 'Leave a patch of nettles in a sunny corner — its caterpillars need them.', 'Leave hibernating butterflies undisturbed in sheds over winter.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('small-tortoiseshell', 'sv', 'Nässelfjäril', 'Denna fjäril övervintrar som vuxen, ofta i skjul och på vindar.', 'Från tidig vår till höst på soliga blommor, särskilt nässlor och buddleja.', 'Lämna en fläck nässlor i ett soligt hörn – dess larver behöver dem.', 'Lämna övervintrande fjärilar i fred i skjul över vintern.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-peacock', 'en', 'European Peacock', 'Its eyespots flash to startle birds, and its wings can hiss when opened.', 'Spring to autumn on sunny days, feeding on thistles, buddleia, and windfall fruit.', 'Let a sunny nettle patch grow for its caterpillars.', 'Do not disturb adults sheltering in sheds and log piles over winter.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-peacock', 'sv', 'Påfågelöga', 'Ögonfläckarna blixtrar till för att skrämma fåglar, och vingarna kan väsa när de öppnas.', 'Vår till höst under soliga dagar, på tistlar, buddleja och fallfrukt.', 'Låt en solig nässelfläck växa för dess larver.', 'Stör inte vuxna fjärilar som söker skydd i skjul och vedhögar över vintern.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('brimstone-butterfly', 'en', 'Common Brimstone', 'The word "butterfly" may come from the male brimstone’s butter-yellow colour.', 'One of the first butterflies of spring; look along woodland edges on warm days.', 'Support buckthorn shrubs in hedges, the only plants its caterpillars eat.', 'Avoid clearing scrubby hedgerows that shelter overwintering adults.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('brimstone-butterfly', 'sv', 'Citronfjäril', 'Det engelska ordet ”butterfly” kan komma från citronfjärilshanens smörgula färg.', 'En av vårens första fjärilar; spana längs skogsbryn under varma dagar.', 'Stöd brakvedsbuskar i häckar, de enda växter dess larver äter.', 'Undvik att röja buskiga häckar som skyddar övervintrande vuxna.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('orange-tip', 'en', 'Orange Tip', 'Only the males have the bright orange wingtips; females are white.', 'In spring along damp meadows and lanes where cuckoo flower grows.', 'Let cuckoo flower and garlic mustard grow in damp, unmown corners.', 'Delay cutting verges until its caterpillars have finished feeding.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('orange-tip', 'sv', 'Aurorafjäril', 'Bara hanarna har de klarorange vingspetsarna; honorna är vita.', 'På våren längs fuktiga ängar och vägkanter där ängsbräsma växer.', 'Låt ängsbräsma och löktrav växa i fuktiga, oklippta hörn.', 'Skjut upp klippning av vägkanter tills larverna ätit färdigt.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-blue', 'en', 'Common Blue', 'The common blue’s caterpillars are sometimes tended by ants for their sweet secretions.', 'From late spring on sunny grassland rich in clover and bird’s-foot trefoil.', 'Leave grassland unmown so trefoils and clovers can flower.', 'Avoid spraying wildflower-rich grassland with weedkiller.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-blue', 'sv', 'Puktörneblåvinge', 'Puktörneblåvingens larver sköts ibland av myror för deras söta utsöndringar.', 'Från sen vår på soliga gräsmarker rika på klöver och käringtand.', 'Lämna gräsmark oklippt så att käringtand och klöver kan blomma.', 'Undvik att spruta blomrika gräsmarker med ogräsmedel.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('green-veined-white', 'en', 'Green-veined White', 'Despite looking like a cabbage white, it prefers wild plants, not garden crops.', 'Spring to late summer in damp meadows, ditches, and woodland rides.', 'Let damp corners grow wild with native crucifers like cuckoo flower.', 'Avoid draining and spraying damp meadows where it breeds.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('green-veined-white', 'sv', 'Rapsfjäril', 'Trots att den liknar en kålfjäril föredrar den vilda växter framför trädgårdsgrödor.', 'Vår till sensommar på fuktiga ängar, diken och skogsstigar.', 'Låt fuktiga hörn växa vilt med inhemska korsblommiga växter som ängsbräsma.', 'Undvik att dika ut och spruta fuktiga ängar där den förökar sig.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('seven-spot-ladybird', 'en', 'Seven-spot Ladybird', 'A single ladybird can eat thousands of aphids in its lifetime.', 'From spring to autumn on plants with aphids; they cluster to hibernate in winter.', 'Tolerate some aphids and skip sprays so ladybirds have food.', 'Leave hollow stems and leaf litter where ladybirds shelter over winter.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('seven-spot-ladybird', 'sv', 'Sjuprickig nyckelpiga', 'En enda nyckelpiga kan äta tusentals bladlöss under sin livstid.', 'Från vår till höst på växter med bladlöss; de samlas för att övervintra.', 'Tolerera en del bladlöss och hoppa över sprutning så att nyckelpigor har föda.', 'Lämna ihåliga stjälkar och löv där nyckelpigor söker skydd över vintern.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('buff-tailed-bumblebee', 'en', 'Buff-tailed Bumblebee', 'Queens are among the first bees out in spring, buzzing low to find nest holes.', 'From early spring to autumn on flowers; queens search hedge bottoms in spring.', 'Grow or leave early-flowering plants and let clover bloom in the lawn.', 'Leave undisturbed banks and old mouse holes where colonies nest.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('buff-tailed-bumblebee', 'sv', 'Mörk jordhumla', 'Drottningarna är bland de första bina ute på våren, surrande lågt för att hitta bohål.', 'Från tidig vår till höst på blommor; drottningar söker häckbottnar på våren.', 'Odla eller lämna tidigblommande växter och låt klöver blomma i gräsmattan.', 'Lämna ostörda slänter och gamla musgångar där kolonier bygger bo.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('western-honey-bee', 'en', 'Western Honey Bee', 'Foragers tell the hive where flowers are by dancing in a figure-of-eight.', 'From spring to autumn on flowers on warm, still days.', 'Let a range of flowers bloom across the seasons and leave a shallow water dish.', 'Avoid spraying flowering plants, and never spray in the middle of the day.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('western-honey-bee', 'sv', 'Honungsbi', 'Samlare talar om för kupan var blommor finns genom att dansa i en åtta.', 'Från vår till höst på blommor under varma, stilla dagar.', 'Låt en mängd blommor blomma över säsongerna och ställ ut ett grunt vattenfat.', 'Undvik att spruta blommande växter, och spruta aldrig mitt på dagen.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('emperor-dragonfly', 'en', 'Emperor Dragonfly', 'One of Europe’s largest dragonflies, it can even catch prey in mid-air.', 'On warm summer days, watch it patrolling ponds and lake margins.', 'Keep or dig a pond with plants and leave its edges vegetated.', 'Keep ponds free of pollution and run-off so larvae can develop.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('emperor-dragonfly', 'sv', 'Kejsartrollslända', 'En av Europas största trollsländor; den kan till och med fånga byte i luften.', 'Under varma sommardagar, se den patrullera dammar och sjökanter.', 'Behåll eller gräv en damm med växter och lämna kanterna bevuxna.', 'Håll dammar fria från föroreningar och avrinning så att larver kan utvecklas.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-darter', 'en', 'Common Darter', 'Darters often perch on the same warm spot, darting out to grab passing insects.', 'From midsummer to autumn near still water, basking on paths and posts.', 'Leave sunny perches and vegetation around ponds and ditches.', 'Avoid letting fertiliser or oil wash into ponds where larvae live.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-darter', 'sv', 'Större ängstrollslända', 'Ängstrollsländor sitter ofta på samma varma plats och rusar ut för att fånga förbipasserande insekter.', 'Från midsommar till höst nära stillastående vatten, solande på stigar och stolpar.', 'Lämna soliga sittplatser och växtlighet kring dammar och diken.', 'Undvik att låta gödsel eller olja rinna ner i dammar där larver lever.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('red-wood-ant', 'en', 'Red Wood Ant', 'Their thatched nest mounds can be over a metre tall and house half a million ants.', 'From spring to autumn in conifer woods; look for domed mounds of needles.', 'Leave nest mounds undisturbed — they take years to build.', 'Keep to paths and never kick or dig into an ant mound.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('red-wood-ant', 'sv', 'Röd skogsmyra', 'Deras tuvbon kan vara över en meter höga och rymma en halv miljon myror.', 'Från vår till höst i barrskog; leta efter kupolformade bon av barr.', 'Lämna myrstackar orörda – de tar år att bygga.', 'Håll dig till stigarna och sparka eller gräv aldrig i en myrstack.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('wood-anemone', 'en', 'Wood Anemone', 'Wood anemones spread so slowly that dense carpets signal ancient woodland.', 'In spring, look for carpets of white flowers before the trees leaf out.', 'Leave woodland floors undisturbed so the slow-spreading roots can thrive.', 'Enjoy them where they grow — picking removes flowers that took years to spread.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('wood-anemone', 'sv', 'Vitsippa', 'Vitsippor sprider sig så långsamt att täta mattor tyder på gammal skog.', 'På våren, leta efter mattor av vita blommor innan träden slår ut.', 'Lämna skogsbottnar ostörda så att de långsamt spridande rötterna kan trivas.', 'Njut av dem där de växer – att plocka tar bort blommor som tagit år att sprida.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('lily-of-the-valley', 'en', 'Lily of the Valley', 'Every part of this sweetly scented plant is poisonous if eaten.', 'In late spring, follow the scent to shady woodland and shaded gardens.', 'Leave shaded woodland edges and leaf litter where it grows.', 'Do not pick or dig it up, and keep it away from children and pets.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('lily-of-the-valley', 'sv', 'Liljekonvalj', 'Hela denna ljuvligt doftande växt är giftig om den äts.', 'På senvåren, följ doften till skuggig skog och skuggiga trädgårdar.', 'Lämna skuggiga skogsbryn och löv där den växer.', 'Plocka eller gräv inte upp den, och håll den borta från barn och husdjur.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('ramsons', 'en', 'Ramsons', 'You often smell ramsons — wild garlic — before you see the white flowers.', 'In spring, look for broad green leaves and starry flowers in damp woods.', 'Leave damp woodland undisturbed so the carpets can regrow each year.', 'If foraging is allowed locally, take only a little and never uproot bulbs.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('ramsons', 'sv', 'Ramslök', 'Man känner ofta lukten av ramslök – vitlöksdoftande – innan man ser de vita blommorna.', 'På våren, leta efter breda gröna blad och stjärnformade blommor i fuktig skog.', 'Lämna fuktig skog ostörd så att mattorna kan växa tillbaka varje år.', 'Om plockning är tillåten lokalt, ta bara lite och dra aldrig upp lökarna.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('marsh-marigold', 'en', 'Marsh Marigold', 'One of the oldest native plants, it survived the last Ice Age in Scandinavia.', 'In spring, look for big golden flowers in marshes, ditches, and pond edges.', 'Keep pond and ditch margins wet and unmown so it can flower.', 'Avoid draining wet ground and leave the plants where they grow.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('marsh-marigold', 'sv', 'Kabbleka', 'En av de äldsta inhemska växterna, den överlevde den senaste istiden i Skandinavien.', 'På våren, leta efter stora gyllene blommor i kärr, diken och dammkanter.', 'Håll damm- och dikeskanter våta och oklippta så att den kan blomma.', 'Undvik att dika ut våt mark och lämna växterna där de växer.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('cowslip', 'en', 'Cowslip', 'Cowslips were once so common in hay meadows that children made them into balls.', 'In spring, look for nodding yellow flowers in old, unimproved meadows.', 'Leave meadows unmown until the cowslips have flowered and set seed.', 'Do not pick or dig them from the wild — meadow flowers are declining.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('cowslip', 'sv', 'Gullviva', 'Gullvivor var förr så vanliga på slåtterängar att barn gjorde bollar av dem.', 'På våren, leta efter nickande gula blommor på gamla, ogödslade ängar.', 'Lämna ängar oklippta tills gullvivorna blommat och satt frö.', 'Plocka eller gräv inte upp dem från det vilda – ängsblommor minskar.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('oxeye-daisy', 'en', 'Oxeye Daisy', 'The oxeye daisy’s flower is actually dozens of tiny flowers packed together.', 'In summer, look for large white daisies along roadsides and meadows.', 'Leave a strip of grass unmown through midsummer so it can flower.', 'Avoid spraying verges and meadows with weedkiller.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('oxeye-daisy', 'sv', 'Prästkrage', 'Prästkragens blomma är egentligen dussintals små blommor tätt samlade.', 'På sommaren, leta efter stora vita prästkragar längs vägkanter och ängar.', 'Lämna en remsa gräs oklippt över midsommar så att den kan blomma.', 'Undvik att spruta vägkanter och ängar med ogräsmedel.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-dandelion', 'en', 'Common Dandelion', 'Dandelions are one of the most important early nectar sources for bees.', 'From spring onwards almost anywhere; flowers open in sun and close at dusk.', 'Let dandelions flower on the lawn in spring before the first mow.', 'Skip lawn weedkillers so early pollinators keep this vital food.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('common-dandelion', 'sv', 'Maskros', 'Maskrosor är en av de viktigaste tidiga nektarkällorna för bin.', 'Från våren nästan var som helst; blommorna öppnar sig i sol och sluter sig i skymningen.', 'Låt maskrosor blomma i gräsmattan på våren före första klippningen.', 'Hoppa över gräsmatteogräsmedel så att tidiga pollinatörer behåller denna viktiga föda.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('heather', 'en', 'Heather', 'A single heather plant can produce over a hundred thousand tiny seeds.', 'In late summer, look for purple carpets on open heaths and bogs.', 'Support keeping heathland open and free of drainage.', 'Keep to paths on heaths and never light fires in dry conditions.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('heather', 'sv', 'Ljung', 'En enda ljungplanta kan producera över hundratusen små frön.', 'På sensommaren, leta efter lila mattor på öppna hedar och myrar.', 'Stöd att hålla hedmark öppen och fri från dikning.', 'Håll dig till stigarna på hedar och tänd aldrig eld i torka.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('bilberry', 'en', 'Bilberry', 'Bilberries stain your fingers blue and feed everything from birds to bears.', 'In summer, look for low bushes with dark berries in pine and spruce forest.', 'Leave forest undergrowth intact so the low bushes can fruit.', 'If picking is allowed locally, leave plenty of berries for wildlife.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('bilberry', 'sv', 'Blåbär', 'Blåbär färgar fingrarna blå och föder allt från fåglar till björnar.', 'På sommaren, leta efter låga buskar med mörka bär i barrskog.', 'Lämna skogens undervegetation intakt så att de låga buskarna kan bära frukt.', 'Om plockning är tillåten lokalt, lämna gott om bär åt djurlivet.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('lingonberry', 'en', 'Lingonberry', 'Lingonberries keep for months thanks to a natural preservative in the fruit.', 'In late summer and autumn, look for glossy red berries on evergreen mats.', 'Leave forest floor vegetation undisturbed so the mats can spread.', 'If picking is allowed locally, tread carefully to avoid crushing the plants.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('lingonberry', 'sv', 'Lingon', 'Lingon håller sig i månader tack vare ett naturligt konserveringsmedel i frukten.', 'På sensommaren och hösten, leta efter blanka röda bär på städsegröna mattor.', 'Lämna skogsbottnens växtlighet ostörd så att mattorna kan sprida sig.', 'Om plockning är tillåten lokalt, trampa försiktigt för att inte krossa växterna.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('silver-birch', 'en', 'Silver Birch', 'A birch supports hundreds of insect species, feeding countless birds.', 'Year-round; the white, peeling bark makes it easy to spot in any season.', 'Leave fallen birch leaves and dead wood to enrich the soil and feed insects.', 'Avoid stripping bark, which can wound and weaken the tree.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('silver-birch', 'sv', 'Vårtbjörk', 'En björk hyser hundratals insektsarter, som föder otaliga fåglar.', 'Året runt; den vita, flagnande barken gör den lätt att känna igen i alla årstider.', 'Lämna fallna björklöv och död ved för att berika jorden och föda insekter.', 'Undvik att skala bark, vilket kan såra och försvaga trädet.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('norway-spruce', 'en', 'Norway Spruce', 'A Norway spruce in Sweden grows from roots that are thousands of years old.', 'Year-round in forests; its drooping cones are the longest of any spruce.', 'Leave fallen cones and dead wood, which shelter insects and fungi.', 'Keep to trails in forests to avoid compacting shallow spruce roots.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('norway-spruce', 'sv', 'Gran', 'En gran i Sverige växer från rötter som är tusentals år gamla.', 'Året runt i skogar; dess hängande kottar är de längsta av alla granar.', 'Lämna fallna kottar och död ved, som hyser insekter och svampar.', 'Håll dig till stigarna i skogen för att inte packa granens ytliga rötter.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('scots-pine', 'en', 'Scots Pine', 'Old Scots pines glow orange near the top and can live for centuries.', 'Year-round on sandy and rocky ground; look for the orange upper bark.', 'Leave standing deadwood and old pines, which are rich in wildlife.', 'Never light fires against or near pines on dry, sandy ground.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('scots-pine', 'sv', 'Tall', 'Gamla tallar lyser orange högt upp och kan bli flera hundra år gamla.', 'Året runt på sandig och stenig mark; leta efter den orange övre barken.', 'Lämna stående död ved och gamla tallar, som är rika på liv.', 'Tänd aldrig eld mot eller nära tallar på torr, sandig mark.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('northern-pike', 'en', 'Northern Pike', 'The pike is an ambush predator that can lunge from stillness in a blink.', 'From spring to autumn in weedy shallows of lakes and slow rivers.', 'Support keeping reedy shallows and water plants where young fish shelter.', 'Keep pollution and litter out of the water; follow local fishing rules.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('northern-pike', 'sv', 'Gädda', 'Gäddan är ett bakhållsrovdjur som kan hugga ur stillhet på ett ögonblick.', 'Från vår till höst i vassrika grunda områden i sjöar och lugna vattendrag.', 'Stöd att bevara vassrika grundområden och vattenväxter där ungfisk söker skydd.', 'Håll föroreningar och skräp borta från vattnet; följ lokala fiskeregler.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-perch', 'en', 'European Perch', 'Perch hunt in packs and wear bold stripes that break up their outline.', 'In the warmer months around jetties, weed beds, and drop-offs.', 'Support clean water and submerged structure that shelters small fish.', 'Never tip anything into lakes and rivers; follow local fishing rules.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('european-perch', 'sv', 'Abborre', 'Abborrar jagar i stim och bär djärva ränder som bryter upp deras siluett.', 'Under de varmare månaderna kring bryggor, vassbälten och branter.', 'Stöd rent vatten och undervattensstruktur som skyddar småfisk.', 'Häll aldrig något i sjöar och vattendrag; följ lokala fiskeregler.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('roach', 'en', 'Common Roach', 'Roach are a key food fish that many lake predators depend on.', 'In the warmer months in shoals near the surface of lakes and slow rivers.', 'Support keeping water clean and margins vegetated for spawning.', 'Keep run-off and litter out of the water; follow local fishing rules.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
insert into public.species_content (species_id, locale, common_name, fact, when_how, give, protect) values ('roach', 'sv', 'Mört', 'Mörten är en viktig bytesfisk som många rovdjur i sjön är beroende av.', 'Under de varmare månaderna i stim nära ytan i sjöar och lugna vattendrag.', 'Stöd att hålla vattnet rent och kanterna bevuxna för lek.', 'Håll avrinning och skräp borta från vattnet; följ lokala fiskeregler.') on conflict (species_id, locale) do update set common_name=excluded.common_name, fact=excluded.fact, when_how=excluded.when_how, give=excluded.give, protect=excluded.protect;
